export const LEARN = {"0":"<b>মূল নিয়ম:</b> কাছের জিনিস বোঝাতে <b>هٰذا</b> (=ইহা), দূরের জিনিস বোঝাতে <b>ذٰلِكَ</b> (=উহা)। এই পাঠের শব্দগুলো <b>পুংলিঙ্গ</b> (ছেলে-জাতীয়)।<br>\n🔹 <span class='ar'>هٰذا كِتابٌ</span> — ইহা একটি বই।<br>\n🔹 <span class='ar'>ذٰلِكَ قَلَمٌ</span> — উহা একটি কলম।<br>\n👉 খেয়াল করো: শব্দের শেষে <b>ــٌ</b> (দুই পেশ/তানভীন) মানে \"একটি/একটা\"।","1":"<b>মূল নিয়ম:</b> <b>স্ত্রীলিঙ্গ</b> (মেয়ে-জাতীয়) শব্দের জন্য <b>هٰذِهِ</b> (=ইহা) ও <b>تِلْكَ</b> (=উহা)। স্ত্রীলিঙ্গ শব্দ সাধারণত শেষে <b>ة</b> (গোল তা) নেয়।<br>\n🔹 <span class='ar'>هٰذِهِ مَدْرَسَةٌ</span> — ইহা একটি মাদরাসা।<br>\n🔹 <span class='ar'>تِلْكَ سَيّارَةٌ</span> — উহা একটি গাড়ি।<br>\n<b>প্রশ্ন করা:</b> <span class='ar'>ما هٰذا؟</span> — ইহা কী? <span class='ar'>ما تِلْكَ؟</span> — উহা কী?","2":"<b>মূল নিয়ম:</b> বিশেষণ (গুণবাচক শব্দ) বসে <b>বিশেষ্যের পরে</b> এবং লিঙ্গে মিল রাখে। স্ত্রীলিঙ্গ হলে বিশেষণেও <b>ة</b> যোগ হয়।<br>\n🔹 <span class='ar'>كِتابٌ جَدِيدٌ</span> — নতুন বই (পুংলিঙ্গ)।<br>\n🔹 <span class='ar'>كُرّاسَةٌ جَدِيدَةٌ</span> — নতুন খাতা (স্ত্রীলিঙ্গ)।<br>\n👉 বিপরীত শব্দ জোড়ায় শেখো: <span class='ar'>كَبِيرٌ / صَغِيرٌ</span> (বড়/ছোট), <span class='ar'>جَدِيدٌ / قَدِيمٌ</span> (নতুন/পুরোনো)।","3":"<b>পুরুষবাচক সর্বনাম:</b> <span class='ar'>أَنا</span> আমি · <span class='ar'>أَنْتَ</span> তুমি · <span class='ar'>هُوَ</span> সে (পুরুষ) · <span class='ar'>هِيَ</span> সে (মেয়ে)।<br>\n🔹 <span class='ar'>أَنا تِلْمِيذٌ</span> — আমি একজন ছাত্র।<br>\n<b>হ্যাঁ/না প্রশ্ন:</b> <span class='ar'>هَلْ</span> দিয়ে প্রশ্ন, উত্তরে <span class='ar'>نَعَمْ</span> (হ্যাঁ) বা <span class='ar'>لا</span> (না)।<br>\n🔹 <span class='ar'>هَلْ أَنْتَ مُعَلِّمٌ؟ لا.. بَلْ أَنا تِلْمِيذٌ</span> — তুমি কি শিক্ষক? না, বরং আমি ছাত্র।","4":"<b>মূল নিয়ম:</b> শব্দের আগে <b>ال</b> যোগ করলে \"টি/টা\" অর্থ হয় অর্থাৎ নির্দিষ্ট হয়। তখন শেষের তানভীন (<span class='ar'>ــٌ</span>) চলে গিয়ে এক পেশ (<span class='ar'>ــُ</span>) হয়।<br>\n🔹 <span class='ar'>كِتابٌ</span> একটি বই → <span class='ar'>اَلْكِتابُ</span> বইটি।<br>\n🔹 <span class='ar'>اَلْبابُ مَفْتُوحٌ</span> — দরজাটি খোলা।<br>\n<b>📌 খুব জরুরি — ال পড়ার দুই নিয়ম:</b><br>\n<b>১) চান্দ্র হরফ (কামারী — ১৪টি):</b> <span class='ar'>ا ب ج ح خ ع غ ف ق ك م هـ و ي</span> — এদের আগে <b>লাম স্পষ্ট</b> পড়া হয়।<br>\n🔹 <span class='ar'>اَلْقَمَرُ</span> (আল-কামার) · <span class='ar'>اَلْكِتابُ</span> (আল-কিতাব) · <span class='ar'>اَلْبَيْتُ</span> (আল-বাইত)।<br>\n<b>২) সূর্য হরফ (শামসী — ১৪টি):</b> <span class='ar'>ت ث د ذ ر ز س ش ص ض ط ظ ل ن</span> — এদের আগে <b>লাম চুপ</b> থাকে, পরের হরফে <b>তাশদীদ</b> পড়তে হয়।<br>\n🔹 <span class='ar'>اَلشَّمْسُ</span> — আশ্‌-শামসু (আল-শামসু ✗) · <span class='ar'>اَلرَّجُلُ</span> — আর্‌-রজুলু · <span class='ar'>اَلنُّورُ</span> — আন্‌-নূরু।<br>\n👉 লেখা একই (<span class='ar'>ال</span>), কিন্তু পড়া আলাদা — এটি না জানলে পড়া শুদ্ধ হবে না।<br>\n<b>নতুন প্রশ্ন:</b> <span class='ar'>كَيْفَ</span> = কেমন? <span class='ar'>كَيْفَ السّاعَةُ؟</span> — ঘড়িটি কেমন?","5":"<b>মূল নিয়ম:</b> শব্দের <b>শেষে</b> ছোট অংশ যোগ করে মালিকানা বোঝানো হয়:<br>\n<b>ـِي</b> আমার · <b>ـكَ</b> তোমার (পুরুষ) · <b>ـكِ</b> তোমার (মেয়ে) · <b>ـهُ</b> তার (পুরুষ) · <b>ـها</b> তার (মেয়ে)।<br>\n🔹 <span class='ar'>كِتابِي</span> আমার বই · <span class='ar'>كِتابُكَ</span> তোমার বই · <span class='ar'>كِتابُها</span> তার বই।<br>\n🔹 <span class='ar'>ما اسْمُكَ؟ اِسْمِي شاهِد</span> — তোমার নাম কী? আমার নাম শাহিদ।<br>\n<b>বহুবচনেও একইভাবে:</b> <b>ـنا</b> আমাদের · <b>ـكُمْ</b> তোমাদের · <b>ـهُمْ</b> তাদের।<br>\n🔹 <span class='ar'>كِتابُنا</span> আমাদের বই · <span class='ar'>كِتابُكُمْ</span> তোমাদের বই।<br>\n👉 এই নিয়মেই ঈমানের সুন্দর বাক্যগুলো তৈরি হয়:<br>\n🔹 <span class='ar'>اَللهُ رَبُّنا</span> — আল্লাহ আমাদের রব · <span class='ar'>اَلْقُرْآنُ كِتابُنا</span> — কুরআন আমাদের কিতাব · <span class='ar'>اَلْكَعْبَةُ قِبْلَتُنا</span> — কাবা আমাদের কিবলা।","6":"<b>মূল নিয়ম (ইদাফা/সম্বন্ধ):</b> দুটি বিশেষ্য পাশাপাশি বসে \"কারো জিনিস\" বোঝায়। প্রথম শব্দে <b>ال</b> বা তানভীন থাকে না, দ্বিতীয় শব্দ <b>ـِ</b> (যের) নেয়।<br>\n🔹 <span class='ar'>كِتابُ راشِدٍ</span> — রাশেদের বই।<br>\n🔹 <span class='ar'>بابُ الْمَسْجِدِ</span> — মসজিদের দরজা।<br>\n👉 বাংলায় যেমন \"রাশেদ + এর + বই\", আরবিতে তেমন উল্টো: <b>বই + রাশেদের</b>।","7":"<b>মূল নিয়ম:</b> <span class='ar'>أَيْنَ</span> = কোথায়? স্থান বোঝাতে এই শব্দগুলো ব্যবহার হয় এবং পরের বিশেষ্য <b>ـِ</b> (যের) নেয়:<br>\n<span class='ar'>عِنْدَ</span> কাছে · <span class='ar'>أَمامَ</span> সামনে · <span class='ar'>وَراءَ</span> পিছনে · <span class='ar'>فَوْقَ</span> উপরে · <span class='ar'>تَحْتَ</span> নিচে · <span class='ar'>بِجانِبِ</span> পাশে।<br>\n🔹 <span class='ar'>اَلسَّماءُ فَوْقَنا وَ الْأَرْضُ تَحْتَنا</span> — আসমান আমাদের উপরে, জমিন আমাদের নিচে।","8":"<b>মূল নিয়ম:</b> <span class='ar'>فِي</span> = ...এর মধ্যে/ভিতরে। <span class='ar'>فِي</span>-এর পরের বিশেষ্য <b>ـِ</b> (যের) নেয়।<br>\n🔹 <span class='ar'>اَلْكِتابُ فِي الْحَقِيبَةِ</span> — বইটি ব্যাগের মধ্যে।<br>\n🔹 <span class='ar'>فِي قَلْبِ الْمُسْلِمِ نُورٌ</span> — মুসলিমের হৃদয়ে আলো।<br>\n👉 প্রশ্ন: <span class='ar'>ماذا؟</span> = কী? <span class='ar'>مَنْ؟</span> = কে? <span class='ar'>مَنْ فِي الْمَسْجِدِ؟</span> — মসজিদে কে?","9":"<b>এই পাঠ একটি রিভিউ:</b> নতুন কিছু শব্দের (শহর, সফর, বিমান) সাথে আগের সব নিয়মের মহড়া — <b>হাজা/হাজিহি</b>, বিশেষণ, <b>ال</b>, <b>في</b> সব একসাথে।<br>\n🔹 <span class='ar'>اَلطّائِرَةُ كَبِيرَةٌ وَ سَرِيعَةٌ</span> — বিমানটি বড় ও দ্রুতগামী।<br>\n🔹 <span class='ar'>ماذا فِي مَطارِ الْعاصِمَةِ؟</span> — রাজধানীর বিমানবন্দরে কী আছে?<br>\n👉 ধীরে ধীরে পড়ে প্রতিটি শব্দের নিয়ম মনে করার চেষ্টা করো।","10":"<b>এই পাঠ শব্দভাণ্ডার বাড়ানোর:</b> হাতিয়ার ও রান্নাঘরের নতুন জিনিসপত্র। আগের <b>হাজা/হাজিহি + বিশেষণ</b> নিয়মেই এগুলো ঝালিয়ে নাও।<br>\n🔹 <span class='ar'>هٰذِهِ دَبّابَةٌ سَرِيعَةٌ</span> — ইহা একটি দ্রুতগামী ট্যাংক।<br>\n🔹 <span class='ar'>ذٰلِكَ سَيْفٌ قَدِيمٌ</span> — উহা একটি পুরোনো তরবারি।<br>\n🔹 <span class='ar'>الْمِلْعَقَةُ فِي الصَّحْنِ</span> — চামচটি থালায়।","11":"<b>মূল নিয়ম:</b> খাবারের গুণ বোঝানো বিশেষণ, লিঙ্গ অনুযায়ী মিল রেখে।<br>\n<span class='ar'>طازَجٌ</span> তাজা · <span class='ar'>بائِتٌ</span> বাসি · <span class='ar'>خالِصٌ</span> খাঁটি · <span class='ar'>فاسِدٌ</span> নষ্ট।<br>\n🔹 <span class='ar'>هٰذا لَبَنٌ خالِصٌ</span> — ইহা খাঁটি দুধ।<br>\n🔹 <span class='ar'>هٰذِهِ الْبَيْضَةُ فاسِدَةٌ</span> — এই ডিমটি নষ্ট (স্ত্রীলিঙ্গে <b>ة</b>)।<br>\n<b>বাছাই প্রশ্ন:</b> <span class='ar'>أَ حُلْوٌ هٰذا أَمْ حامِضٌ؟</span> — এটা কি মিষ্টি না টক?","12":"<b>মূল নিয়ম:</b> কিছু বিশেষণের শেষে <b>ـٍ</b> থাকে; স্ত্রীলিঙ্গে তা <b>ـِيَةٌ</b> হয়।<br>\n<span class='ar'>عالٍ</span> উঁচু → স্ত্রীঃ <span class='ar'>عالِيَةٌ</span> · <span class='ar'>غالٍ</span> দামী · <span class='ar'>قَلِيلٌ</span> কম · <span class='ar'>كَثِيرٌ</span> বেশি।<br>\n🔹 <span class='ar'>هٰذَا الْجَبَلُ عالٍ</span> — এই পাহাড়টি উঁচু।<br>\n🔹 <span class='ar'>هٰذِهِ الْمَنارَةُ عالِيَةٌ</span> — এই মিনারটি উঁচু।","13":"<b>মূল নিয়ম:</b> <span class='ar'>غَيْر</span> দিয়ে \"নয়/অ-\" বোঝানো হয় — গুণের বিপরীত বানায়। পরের শব্দ <b>ـٍ</b> (যের-তানভীন) নেয়।<br>\n🔹 <span class='ar'>ماهِرٌ</span> দক্ষ → <span class='ar'>غَيْرُ ماهِرٍ</span> অদক্ষ।<br>\n🔹 <span class='ar'>راشِدٌ لاعِبٌ ماهِرٌ وَ أَنْتَ لاعِبٌ غَيْرُ ماهِرٍ</span> — রাশেদ দক্ষ খেলোয়াড়, আর তুমি অদক্ষ খেলোয়াড়।<br>\n👉 পেশা+চরিত্রের শব্দ শেখো: <span class='ar'>طَبِيبٌ, كاتِبٌ, نَشِيطٌ, كَسْلانُ</span>।","14":"<b>মূল নিয়ম:</b> <span class='ar'>وَ</span> (=এবং) দিয়ে দুটি বাক্য বা শব্দ জোড়া লাগানো যায়।<br>\n🔹 <span class='ar'>الْقَلَمُ جَيِّدٌ وَ الْمِسْطَرَةُ جَيِّدَةٌ</span> — কলমটি ভালো এবং রুলারটিও ভালো।<br>\n🔹 <span class='ar'>الْبابُ مَفْتُوحٌ وَ النّافِذَةُ مُغْلَقَةٌ</span> — দরজা খোলা এবং জানালা বন্ধ।<br>\n<b>বাছাই প্রশ্ন:</b> <span class='ar'>أَ تُفّاحَةٌ تِلْكَ أَمْ رُمّانَةٌ؟</span> — ওটা কি আপেল, না আনার?","15":"<b>এই পাঠ শব্দভাণ্ডার বাড়ানোর:</b> নানা প্রাণীর নাম। আগের সব নিয়ম (এই/ঐ, বিশেষণ, ال) দিয়ে বাক্য বানাও।<br>\n👉 লিঙ্গ খেয়াল রাখো — কিছু প্রাণী পুংলিঙ্গ, কিছু স্ত্রীলিঙ্গ।<br>\n🔹 ছবি দেখে শব্দ মেলানোর অনুশীলন দিয়ে প্রাণীগুলো দ্রুত মনে থাকবে, ইনশাআল্লাহ।","16":"<b>এই পাঠ শব্দভাণ্ডার বাড়ানোর:</b> শরীর ও চেহারার অঙ্গ-প্রত্যঙ্গ।<br>\n👉 খেয়াল করো, দেহের জোড়া অঙ্গ (চোখ <span class='ar'>عَيْنٌ</span>, হাত <span class='ar'>يَدٌ</span>) সাধারণত <b>স্ত্রীলিঙ্গ</b>, তাই এদের বিশেষণে <b>ة</b> আসে।<br>\n🔹 আগের মালিকানা-নিয়ম কাজে লাগাও: <span class='ar'>ـِي, ـكَ, ـهُ</span> (আমার/তোমার/তার হাত ইত্যাদি)।","17":"<b>মূল নিয়ম (বাক্য গঠনের সিঁড়ি):</b> ছোট থেকে বড় বাক্য ধাপে ধাপে বানাও। বিশেষ্যে <b>ال</b> থাকলে তার বিশেষণেও <b>ال</b> আসে।<br>\n🔹 <span class='ar'>كِتابٌ</span> — একটি বই।<br>\n🔹 <span class='ar'>كِتابٌ جَدِيدٌ</span> — একটি নতুন বই।<br>\n🔹 <span class='ar'>اَلْكِتابُ الْجَدِيدُ جَمِيلٌ</span> — নতুন বইটি সুন্দর।<br>\n👉 এই ধাপ বোঝা মানে আরবি বাক্যের কাঠামো ধরে ফেলা।","18":"<b>মূল নিয়ম (অতীত কাল):</b> কোনো কাজ হয়ে গেছে বোঝাতে অতীত ক্রিয়া। কে করেছে তা শেষে বোঝা যায়:<br>\n<span class='ar'>فَعَلَ</span> সে করেছে · <span class='ar'>فَعَلْتَ</span> তুমি করেছ · <span class='ar'>فَعَلْتُ</span> আমি করেছি।<br>\n🔹 <span class='ar'>نَصَرَ</span> সে সাহায্য করেছে · <span class='ar'>كَتَبَ</span> সে লিখেছে।<br>\n👉 মূল তিন হরফ ঠিক রেখে শুধু শেষ অংশ বদলায় — এটাই আরবি ক্রিয়ার মজা।","19":"<b>মূল নিয়ম (হরফে জার):</b> এই ছোট শব্দগুলোর পরের বিশেষ্য <b>ـِ</b> (যের) নেয়:<br>\n<span class='ar'>مِنْ</span> থেকে · <span class='ar'>إِلى</span> দিকে · <span class='ar'>عَلى</span> উপরে · <span class='ar'>بِـ</span> দিয়ে/সাথে।<br>\n🔹 <span class='ar'>مِنَ الْبَيْتِ إِلَى الْمَسْجِدِ</span> — ঘর থেকে মসজিদের দিকে।<br>\n🔹 <span class='ar'>الْكِتابُ عَلَى الطّاوِلَةِ</span> — বইটি টেবিলের উপরে।","20":"<b>মূল নিয়ম (বর্তমান-ভবিষ্যৎ):</b> চলমান বা হবে এমন কাজ বোঝাতে ক্রিয়ার শুরুতে অক্ষর যোগ হয়:<br>\n<span class='ar'>يَفْعَلُ</span> সে করে/করছে · <span class='ar'>أَفْعَلُ</span> আমি করি · <span class='ar'>تَفْعَلُ</span> তুমি করো।<br>\n🔹 ভবিষ্যতের জন্য আগে <span class='ar'>سَـ</span> / <span class='ar'>سَوْفَ</span>: <span class='ar'>سَيَفْعَلُ</span> সে করবে।<br>\n👉 অতীত <span class='ar'>فَعَلَ</span> আর বর্তমান <span class='ar'>يَفْعَلُ</span>—এই দুই রূপ মিলিয়ে শেখো।","21":"<b>মূল নিয়ম (না-বাচক):</b> কাজ হয়নি/হয় না বোঝাতে —<br>\n<span class='ar'>ما</span> + অতীত = করেনি (<span class='ar'>ما فَعَلَ</span>)।<br>\n<span class='ar'>لا</span> + বর্তমান = করে না (<span class='ar'>لا يَفْعَلُ</span>)।<br>\n<span class='ar'>لَنْ</span> + বর্তমান = কখনো করবে না (<span class='ar'>لَنْ يَفْعَلَ</span>)।<br>\n👉 কোন সময়ের না-বাচক, তা দেখে সঠিক শব্দ বাছাই করো।","22":"<b>মূল নিয়ম (আদেশ ও নিষেধ):</b><br>\nআদেশ: <span class='ar'>اِفْعَلْ</span> করো! যেমন <span class='ar'>اِقْرَأْ</span> পড়ো · <span class='ar'>اُكْتُبْ</span> লেখো।<br>\nনিষেধ: <span class='ar'>لا تَفْعَلْ</span> করো না! যেমন <span class='ar'>لا تَكْذِبْ</span> মিথ্যা বলো না।<br>\n👉 আদেশ = সরাসরি কাউকে কিছু করতে বলা; নিষেধে সামনে <span class='ar'>لا تَـ</span> বসে।","23":"<b>মূল নিয়ম (কর্মসহ ক্রিয়া):</b> কিছু ক্রিয়ার একটি <b>কর্ম</b> (কাকে/কী) লাগে। কর্ম শেষে <b>ـَ</b> (যবর) নেয়।<br>\n🔹 <span class='ar'>نَصَرَ اللهُ الْمُؤْمِنَ</span> — আল্লাহ মুমিনকে সাহায্য করেছেন।<br>\n<span class='ar'>عَرَفَ</span> চিনেছে · <span class='ar'>حَفِظَ</span> মুখস্থ করেছে/রক্ষা করেছে।<br>\n<b>প্রশ্ন:</b> <span class='ar'>مَنْ؟</span> কাকে? <span class='ar'>ماذا؟</span> কী?","24":"<b>মূল নিয়ম:</b> কর্মের সর্বনাম ক্রিয়ার <b>শেষে</b> জুড়ে যায়:<br>\n<span class='ar'>ـنِي</span> আমাকে · <span class='ar'>ـكَ</span> তোমাকে · <span class='ar'>ـهُ</span> তাকে।<br>\n🔹 <span class='ar'>نَصَرَنِي</span> সে আমাকে সাহায্য করেছে।<br>\nনতুন ক্রিয়া: <span class='ar'>خَلَقَ</span> সৃষ্টি করেছেন · <span class='ar'>سَجَدَ</span> সিজদা করেছে।<br>\n🔹 <span class='ar'>خَلَقَنا اللهُ</span> — আল্লাহ আমাদের সৃষ্টি করেছেন।","25":"<b>মূল নিয়ম (বাব ইফআল):</b> মূল ক্রিয়ার শুরুতে <b>أَ</b> যোগ করলে অর্থ হয় \"করানো/পৌঁছে দেওয়া\"।<br>\n🔹 <span class='ar'>نَزَلَ</span> নামল → <span class='ar'>أَنْزَلَ</span> নাযিল করলেন।<br>\n🔹 <span class='ar'>أَرْسَلَ</span> পাঠালেন · <span class='ar'>أَطْعَمَ</span> খাওয়ালেন।<br>\n🔹 <span class='ar'>أَنْزَلَ اللهُ الْقُرْآنَ</span> — আল্লাহ কুরআন নাযিল করেছেন।","26":"<b>মূল নিয়ম (জওফ ক্রিয়া):</b> যেসব ক্রিয়ার <b>মাঝের হরফ</b> ছিল <span class='ar'>و / ي</span>, অতীতে তা <span class='ar'>ا</span> হয়ে যায়।<br>\n🔹 <span class='ar'>قالَ</span> বলল · <span class='ar'>نامَ</span> ঘুমাল · <span class='ar'>خافَ</span> ভয় পেল।<br>\nবর্তমানে ফিরে আসে: <span class='ar'>يَقُولُ, يَنامُ, يَخافُ</span>।<br>\n👉 তাই এদের চেনা একটু আলাদা — মাঝের অক্ষরের দিকে খেয়াল রাখো।","27":"<b>মূল নিয়ম (উদ্দেশ্য ও ইচ্ছা):</b><br>\n<span class='ar'>لِـ</span> + ক্রিয়া = \"...করার জন্য\"। <span class='ar'>لِيَقْرَأَ</span> পড়ার জন্য।<br>\n<span class='ar'>أُرِيدُ أَنْ</span> = আমি চাই যে...। <span class='ar'>أُرِيدُ أَنْ أَقْرَأَ</span> — আমি পড়তে চাই।<br>\n👉 এই <span class='ar'>لِـ</span> ও <span class='ar'>أَنْ</span>-এর পরে ক্রিয়ার শেষ যবর (<span class='ar'>ـَ</span>) হয়।","28":"<b>মূল নিয়ম:</b> অবস্থা বোঝানো তিন শব্দ:<br>\n<span class='ar'>كانَ</span> ছিল · <span class='ar'>صارَ</span> হয়ে গেল · <span class='ar'>لَيْسَ</span> নয়।<br>\n🔹 <span class='ar'>كانَ الْجَوُّ بارِدًا</span> — আবহাওয়া ঠাণ্ডা ছিল।<br>\n👉 এদের পরের খবর (গুণ) <b>ـً</b>/<b>ـَ</b> (যবর) নেয় — যেমন <span class='ar'>بارِدًا</span>।<br>\n🔹 <span class='ar'>لَيْسَ الْبابُ مَفْتُوحًا</span> — দরজাটি খোলা নয়।","29":"<b>মূল নিয়ম (নাকিস ক্রিয়া):</b> যেসব ক্রিয়ার <b>শেষ হরফ</b> <span class='ar'>و / ي / ا</span>।<br>\n🔹 <span class='ar'>دَعا</span> ডাকল · <span class='ar'>بَنى</span> বানাল · <span class='ar'>صَلّى</span> নামায পড়ল।<br>\n🔹 <span class='ar'>دَعا الْمُسْلِمُ رَبَّهُ</span> — মুসলিম তার রবকে ডাকল।<br>\n👉 শেষ অক্ষরটি একটু বদলায়, তাই এদের আলাদা করে চেনা জরুরি।","30":"<b>মূল নিয়ম (জিনিসের বহুবচন):</b> আরবিতে বহুবচনে শব্দের গড়নই বদলে যায় (ভাঙা বহুবচন)।<br>\n🔹 <span class='ar'>كِتابٌ</span> বই → <span class='ar'>كُتُبٌ</span> বইগুলো।<br>\n🔹 <span class='ar'>قَلَمٌ</span> → <span class='ar'>أَقْلامٌ</span> · <span class='ar'>بَيْتٌ</span> → <span class='ar'>بُيُوتٌ</span>।<br>\n👉 এক-দুই নিয়মে ধরা যায় না; উদাহরণ দেখে দেখে মুখস্থ করাই সহজ।","31":"<b>মূল নিয়ম (মানুষের বহুবচন):</b> পুরুষ-জাতীয় মানুষের বহুবচনে শেষে <span class='ar'>ـُونَ</span> আসে।<br>\n🔹 <span class='ar'>مُسْلِمٌ</span> → <span class='ar'>مُسْلِمُونَ</span> মুসলিমগণ।<br>\n\"তারা\" বোঝাতে ক্রিয়া: <span class='ar'>فَعَلُوا</span> তারা করেছে · <span class='ar'>يَفْعَلُونَ</span> তারা করে।<br>\n🔹 <span class='ar'>الْمُسْلِمُونَ يَعْبُدُونَ اللهَ</span> — মুসলিমগণ আল্লাহর ইবাদত করে।","32":"<b>মূল নিয়ম (সংখ্যা):</b> আরবি অঙ্ক: <span class='ar'>٠ ١ ٢ ٣ ٤ ٥ ٦ ٧ ٨ ٩</span>।<br>\n<span class='ar'>واحِدٌ</span> ১ · <span class='ar'>اِثْنانِ</span> ২ · <span class='ar'>ثَلاثَةٌ</span> ৩ · <span class='ar'>أَرْبَعَةٌ</span> ৪ · <span class='ar'>خَمْسَةٌ</span> ৫ ... <span class='ar'>عَشَرَةٌ</span> ১০।<br>\n👉 অঙ্কের চেহারা ও নাম—দুটোই চিনে রাখো, দৈনন্দিন কাজে খুব দরকারি।","33":"<b>মূল নিয়ম (তুলনা):</b> \"বেশি/অধিক\" বোঝাতে <span class='ar'>أَفْعَلُ مِنْ</span> কাঠামো।<br>\n🔹 <span class='ar'>كَبِيرٌ</span> বড় → <span class='ar'>أَكْبَرُ مِنْ</span> ...থেকে বড়।<br>\n🔹 <span class='ar'>أَفْضَلُ مِنْ</span> ...থেকে উত্তম।<br>\n🔹 <span class='ar'>اَلْعِلْمُ أَفْضَلُ مِنَ الْمالِ</span> — জ্ঞান সম্পদের চেয়ে উত্তম।","34":"<b>মূল নিয়ম:</b><br>\n<span class='ar'>اَلَّذِي</span> = যে (পুরুষ) · <span class='ar'>اَلَّتِي</span> = যে (মেয়ে) · <span class='ar'>مَنْ</span> = যে/যারা।<br>\n🔹 <span class='ar'>جاءَ الَّذِي عَرَفْتَهُ</span> — যাকে তুমি চিনতে সে এসেছে।<br>\nশর্ত: <span class='ar'>إِنْ</span> / <span class='ar'>لَوْ</span> = যদি। <span class='ar'>إِنْ تَجْتَهِدْ تَنْجَحْ</span> — যদি চেষ্টা করো, সফল হবে।","35":"<b>এই শেষ পাঠে:</b> এতদিন যা শিখলে, তা দিয়ে সরাসরি <b>কুরআন ও হাদীসের সহজ বাক্য</b> বোঝার চেষ্টা করো — এটাই ছিল লক্ষ্য!<br>\n🔹 <span class='ar'>اَلْقُرْآنُ كِتابُ اللهِ</span> — কুরআন আল্লাহর কিতাব।<br>\n🔹 <span class='ar'>اَلْكَعْبَةُ بَيْتُ اللهِ</span> — কাবা আল্লাহর ঘর।<br>\n👉 প্রতিটি শব্দে থেমে থেমে নিয়ম মিলিয়ে পড়ো — আল্লাহর কালামের স্বাদ নাও। বারাকাল্লাহু ফীক!","36":"<b>মূল নিয়ম (নিদা = সম্বোধন):</b> কাউকে ডাকার জন্য আরবিতে তিনটি রূপ:<br>\n<b>১) <span class='ar'>يا</span></b> — নাম বা সাধারণ শব্দের আগে: <span class='ar'>يا بِلالُ!</span> হে বিলাল! · <span class='ar'>يا وَلَدُ!</span> হে ছেলে!<br>\n👉 খেয়াল করো: <span class='ar'>يا</span>-এর পরের শব্দ <b>পেশ</b> নেয়, তানভীন নয় (<span class='ar'>يا وَلَدُ</span>, <span class='ar'>يا وَلَدٌ</span> নয়)।<br>\n<b>২) <span class='ar'>أَيُّها</span></b> — <b>ال</b>-ওয়ালা পুংলিঙ্গ শব্দের আগে: <span class='ar'>أَيُّهَا الْمُسْلِمُ!</span> হে মুসলিম!<br>\n<b>৩) <span class='ar'>أَيَّتُها</span></b> — <b>ال</b>-ওয়ালা স্ত্রীলিঙ্গ শব্দের আগে: <span class='ar'>أَيَّتُهَا الْبِنْتُ!</span> হে মেয়ে!<br>\n<b>📌 নামের তানভীনের নিয়ম:</b> ছেলেদের নামে তানভীন হয় — <span class='ar'>خالِدٌ، راشِدٌ، مَحْمُودٌ</span>; কিন্তু মেয়েদের নামে তানভীন <b>হয় না</b> — <span class='ar'>فاطِمَةُ، عائِشَةُ، زَيْنَبُ</span>।","37":"<b>মূল নিয়ম (মাসদার):</b> প্রতিটি ক্রিয়ার একটি নাম আছে — সেটিই <b>মাসদার</b>। বাংলায় যেমন \"পড়েছে\" থেকে \"পড়া\"।<br>\n🔹 <span class='ar'>قَرَأَ</span> পড়েছে → <span class='ar'>اَلْقِراءَةُ</span> পড়া।<br>\n🔹 <span class='ar'>كَتَبَ</span> লিখেছে → <span class='ar'>اَلْكِتابَةُ</span> লেখা · <span class='ar'>نَجَحَ</span> → <span class='ar'>اَلنَّجاحُ</span> সফলতা।<br>\n👉 মাসদার একটি <b>বিশেষ্য</b>, তাই বাক্যের শুরুতেও বসতে পারে: <span class='ar'>اَلْقِراءَةُ مُفِيدَةٌ</span> — পড়া উপকারী।<br>\n<b>দ্বিতীয় নিয়ম (অভ্যাসের অতীত):</b> <span class='ar'>كانَ</span> + মুদারি (বর্তমান) = আগে নিয়মিত করত।<br>\n🔹 <span class='ar'>كانَ راشِدٌ يَقْرَأُ كُلَّ يَوْمٍ</span> — রাশেদ প্রতিদিন পড়ত।<br>\n🔹 <span class='ar'>كانَتْ فاطِمَةُ تَكْتُبُ</span> — ফাতেমা লিখত।<br>\n👉 শুধু <span class='ar'>قَرَأَ</span> বললে \"একবার পড়েছে\", কিন্তু <span class='ar'>كانَ يَقْرَأُ</span> বললে \"নিয়মিত পড়ত\" — পার্থক্যটা মনে রেখো।","38":"<b>মূল নিয়ম (জাওয়াবের হরফ):</b><br>\n<span class='ar'>نَعَمْ</span> হ্যাঁ · <span class='ar'>لا</span> না · <span class='ar'>بَلْ</span> বরং।<br>\n🔹 <span class='ar'>هَلْ هُوَ مُعَلِّمٌ؟ لا.. بَلْ هُوَ تِلْمِيذٌ</span> — সে কি শিক্ষক? না, বরং সে ছাত্র।<br>\n<b>📌 <span class='ar'>بَلى</span> — সবচেয়ে মজার নিয়ম:</b> প্রশ্নটি যদি <b>না-বোধক</b> হয়, তখন \"হ্যাঁ, করেছি\" বলতে <span class='ar'>نَعَمْ</span> নয়, বলতে হয় <span class='ar'>بَلى</span>।<br>\n🔹 <span class='ar'>أَ ما ذَهَبْتَ؟</span> তুমি যাও নি? <br>\n&nbsp;&nbsp;— <span class='ar'>بَلى.. ذَهَبْتُ</span> = হ্যাঁ, (বরং) গিয়েছি!<br>\n&nbsp;&nbsp;— <span class='ar'>نَعَمْ.. ما ذَهَبْتُ</span> = হ্যাঁ (ঠিকই), যাই নি।<br>\n👉 অর্থাৎ <span class='ar'>نَعَمْ</span> প্রশ্নটিকে সমর্থন করে, আর <span class='ar'>بَلى</span> প্রশ্নটিকে <b>ভুল প্রমাণ</b> করে।<br>\n<b>বাছাই প্রশ্ন <span class='ar'>أ ... أَمْ</span>:</b> <span class='ar'>أَ قَلَمٌ هٰذا أَمْ مِفْتاحٌ؟</span> — এটি কি কলম, না চাবি? উত্তরে শুধু নামটি বলো।"};
